#include <stdio.h>

int main(void) {
    int left = 0, right = 0;
    int n = 0, m = 0, k = 0;
    int i = 1, val = 1;

    scanf("%d %d %d", &n, &m, &k);
    left = right = k;
    m -= n;

    while (m >= i) {
        val++;
        m -= i;
        if (left > 1) {
            left--;
            i++;
        }

        if (right < n) {
            right++;
            i++;
        }

        if (left == 1 && right == n) {
            val = val + m / n;
            break;
        }
    }

    printf("%d\n", val);

    return 0;
}

