use std::cmp::*;

const INF: i64 = 2000000000;
fn main() {
    let (n, m, k) = {
        let r = getvec::<i64>();
        (r[0], r[1], r[2])
    };
    let num = m - n;
    let l_n = k;
    let r_n = n - k + 1;
    let mut lb = 0i64;
    let mut ub = INF;
    while ub - lb > 1i64 {
        let mid = (ub + lb) / 2;
        let r = calc(max(1i64, mid - r_n + 1), mid);
        let l = calc(max(1i64, mid - l_n + 1), mid);
        let res = r + l - mid;
        if res <= num {
            lb = mid;
        } else {
            ub = mid;
        }
    }
    println!("{}", lb + 1);
}

fn calc(l: i64, r: i64) -> i64 {
    let n = r - l + 1;
    let res = n * (l + r);
    res / 2
}

